SELECT ?aLabel ?p ?o ?oLabel (ISIRI(?o) AS ?oIri) WHERE {
  VALUES ?anchor { <http://purl.obolibrary.org/obo/UBERON_0001840> }
  ?anchor <http://www.w3.org/2000/01/rdf-schema#label> ?aLabel ; ?p ?o .
  FILTER(STRSTARTS(STR(?p), "https://het.io/schema/"))
  OPTIONAL { ?o <http://www.w3.org/2000/01/rdf-schema#label> ?oLabel }
} ORDER BY ?aLabel ?p ?o LIMIT 5000

